using System.IO;
public static class Phase3SceneBuilder
{
    private static void CreateTitle(Transform parent)
    {
        var title = CreateText(parent, "Text_Title", "Phase3 Graybox Prototype", 42, TextAnchor.MiddleCenter);
        var rect = title.GetComponent<RectTransform>();
        rect.anchorMin = new Vector2(0.5f, 1f);
        rect.anchorMax = new Vector2(0.5f, 1f);
        rect.pivot = new Vector2(0.5f, 1f);
        rect.anchoredPosition = new Vector2(0f, -32f);
        rect.sizeDelta = new Vector2(900f, 70f);
    }
    private static void CreatePanel(Transform parent, string panelName, string label, Vector2 position, Vector2 size, Color color)
    {
        var panel = new GameObject(panelName, typeof(RectTransform), typeof(CanvasRenderer), typeof(Image));
        panel.transform.SetParent(parent, false);
        panel.layer = LayerMask.NameToLayer("UI");

        var rect = panel.GetComponent<RectTransform>();
        rect.anchorMin = new Vector2(0.5f, 0.5f);
        rect.anchorMax = new Vector2(0.5f, 0.5f);
        rect.pivot = new Vector2(0.5f, 0.5f);
        rect.anchoredPosition = position;
        rect.sizeDelta = size;

        var image = panel.GetComponent<Image>();
        image.color = color;

        var text = CreateText(panel.transform, "Text_" + label.Replace(" ", string.Empty), label, 28, TextAnchor.MiddleCenter);
        var textRect = text.GetComponent<RectTransform>();
        textRect.anchorMin = Vector2.zero;
        textRect.anchorMax = Vector2.one;
        textRect.offsetMin = Vector2.zero;
        textRect.offsetMax = Vector2.zero;
    }
